class Solution {
    public String reverseParentheses(String s) {
        int n = s.length();
        int[] open = new int[n];
        int[] close = new int[n];
        int top = -1;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '(') {
                open[++top] = i;
            } else if (s.charAt(i) == ')') {
                close[open[top--]] = i;
            }
        }
        StringBuilder res = new StringBuilder();
        int dir = 1;
        for (int i = 0; i < n; i += dir) {
            char c = s.charAt(i);
            if (c == '(' || c == ')') {
                i = close[i];
                dir = -dir;
            } else {
                res.append(c);
            }
        }
        return res.toString();
    }
}
```
